SELECT d.name, d.site_name
FROM devices d
WHERE julianday('now') - julianday(d.last_seen) > 30;

SELECT site_name, COUNT(device_id) AS device_count
FROM devices
GROUP BY site_name;

SELECT DISTINCT serial_number
FROM devices
WHERE site_name = 'Site 1';

SELECT d.device_id, d.site_name
FROM devices d
WHERE d.last_firmware_update = (
  SELECT MAX(last_firmware_update) AS max_update
  FROM devices
);

SELECT 
  (SELECT MAX(time_generated) FROM devices WHERE device_id = 0) AS latest_time_generated,
  (SELECT COUNT(*) FROM maintenance_records WHERE device_id = 0) AS maintenance_record_count;
